cd /tmp/sv-da4a7592b13f46e3951cf79f5daec37a/moderate-version-conflicts && dotnet package list --format json > after-cpm-packages.json 2>&1 && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs.setdefault(name, {})[pkg['id']] = pkg.get('resolvedVersion', pkg.get('requestedVersion','?'))
    return pkgs

b = extract(baseline)
a = extract(after)
print('=== Version changes ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg, 'N/A')
        av = a.get(proj,{}).get(pkg, 'N/A')
        if bv != av:
            print(f'  {proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('  (none)')
"

